def trimmed_mean(nums):
    if not nums:
        return None

    nums = sorted(nums)
    if len(nums) <= 1:
        return sum(nums) / len(nums)

    min_index, max_index = 1, len(nums)-2
    total = 0
    for i in range(len(nums)):
        if i not in (min_index, max_index):
            total += nums[i]

    return total / (len(nums) - 2)
